```{.r .cell-code}
ui <- fluidPage(
  titlePanel("Stock Analysis with Quantmod"),
  tabsetPanel(
    tabPanel("Bollinger Bands", 
             sidebarLayout(
               sidebarPanel(
                 textInput("bb_ticker", "Enter Stock Ticker:", "AAPL"),
                 dateRangeInput("bb_dateRange", "Select Date Range:", 
                                start = Sys.Date() - 365, 
                                end = Sys.Date()),
                 actionButton("bb_goButton", "Show Bollinger Bands")
               ),
               mainPanel(
                 plotOutput("bb_chart")
               )
             )),
    tabPanel("RSI", 
             sidebarLayout(
               sidebarPanel(
                 textInput("rsi_ticker", "Enter Stock Ticker:", "AAPL"),
                 dateRangeInput("rsi_dateRange", "Select Date Range:", 
                                start = Sys.Date() - 365, 
                                end = Sys.Date()),
                 actionButton("rsi_goButton", "Show RSI")
               ),
               mainPanel(
                 plotOutput("rsi_chart")
               )
             ))
  )
)

server <- function(input, output) {
  observeEvent(input$bb_goButton, {
    req(input$bb_ticker)
    stockData <- getSymbols(input$bb_ticker, src = "yahoo", 
                            from = input$bb_dateRange[1], to = input$bb_dateRange[2], 
                            auto.assign = FALSE)
    output$bb_chart <- renderPlot({
      if (!is.null(stockData)) {
        chartSeries(stockData, name = input$bb_ticker, theme = chartTheme("white"))
        addBBands(n = 20, sd = 2)
      }
    })
  })

  observeEvent(input$rsi_goButton, {
    req(input$rsi_ticker)
    stockData <- getSymbols(input$rsi_ticker, src = "yahoo", 
                            from = input$rsi_dateRange[1], to = input$rsi_dateRange[2], 
                            auto.assign = FALSE)
    output$rsi_chart <- renderPlot({
      if (!is.null(stockData)) {
        chartSeries(stockData, name = input$rsi_ticker, theme = chartTheme("white"))
        addRSI()
      }
    })
  })
}

shinyApp(ui = ui, server = server)
```

